// Generated by AI (UnitTest MCP)
use crate::{decay, now_unix, Knowledge, Lodestar, Result, SignalPromotion};

/// Gating thresholds for consolidation (ADR-0005: don't launder coincidence).
const MIN_EVIDENCE_COUNT: usize = 3;
const MIN_EVIDENCE_SPAN_SECS: i64 = 3 * 24 * 3600; // proven across days, not one session

impl Lodestar {
    pub fn record_knowledge(
        &self,
        statement: &str,
        evidence: &str,
        half_life_hours: Option<f64>,
    ) -> Result<Knowledge> {
        let hl = half_life_hours.unwrap_or(decay::KNOWLEDGE_DEFAULT_HALF_LIFE_HOURS);
        self.store
            .record_knowledge(statement, evidence, hl, now_unix())
    }

    pub fn active_knowledge(&self) -> Result<Vec<Knowledge>> {
        self.store.active_knowledge(now_unix())
    }

    pub fn reconfirm_knowledge(&self, id: &str) -> Result<bool> {
        self.store.reconfirm_knowledge(id, now_unix())
    }

    pub fn prune_knowledge(&self) -> Result<usize> {
        self.store.prune_knowledge(now_unix())
    }

    /// Gated promotion of a discovered regularity into durable knowledge. Returns
    /// `None` (and stores nothing) unless the evidence clears the count and span
    /// thresholds — signal, not coincidence (ADR-0005).
    pub fn consolidate(
        &self,
        statement: &str,
        evidence_node_ids: &[String],
        first_seen: i64,
        last_seen: i64,
    ) -> Result<Option<Knowledge>> {
        if evidence_node_ids.len() < MIN_EVIDENCE_COUNT
            || (last_seen - first_seen) < MIN_EVIDENCE_SPAN_SECS
        {
            return Ok(None);
        }
        let evidence = serde_json::json!({
            "nodes": evidence_node_ids,
            "count": evidence_node_ids.len(),
            "first_seen": first_seen,
            "last_seen": last_seen,
        })
        .to_string();
        let k = self.store.record_knowledge(
            statement,
            &evidence,
            decay::KNOWLEDGE_DEFAULT_HALF_LIFE_HOURS,
            now_unix(),
        )?;
        Ok(Some(k))
    }
}

/// The deterministic, model-free statement for a candidate that arrives without a
/// pre-distilled summary. Kept templated (not an LLM call) so promotion works with
/// no local model on any path (ADR-0022).
fn templated_statement(candidate: &SignalPromotion) -> String {
    format!(
        "proven regularity around {}: reinforced across {} corroborating signals",
        candidate.subject,
        candidate.evidence_node_ids.len()
    )
}

impl Lodestar {
    /// Promotion bridge (ADR-0022): feed MindLeak proven-signal candidates into the
    /// existing gated [`consolidate`](Self::consolidate). Reuses the count + span
    /// gate — it invents no new threshold, so same-session spam and one-offs are
    /// rejected exactly as today. Deterministic and model-optional: a candidate
    /// without a pre-distilled `statement` gets a templated one. Returns the
    /// candidates that cleared the gate and were stored.
    pub fn promote_signals(&self, candidates: &[SignalPromotion]) -> Result<Vec<Knowledge>> {
        let mut promoted = Vec::new();
        for candidate in candidates {
            let statement = candidate
                .statement
                .clone()
                .unwrap_or_else(|| templated_statement(candidate));
            if let Some(knowledge) = self.consolidate(
                &statement,
                &candidate.evidence_node_ids,
                candidate.first_seen,
                candidate.last_seen,
            )? {
                promoted.push(knowledge);
            }
        }
        Ok(promoted)
    }
}

#[cfg(test)]
mod tests {
    use crate::facade::test_support::engine;
    use crate::SignalPromotion;

    #[test]
    fn consolidation_gate_rejects_coincidence_and_accepts_proven_signal() {
        let e = engine();
        // Too few, too fast: not promoted.
        let weak = e
            .consolidate("X flakes", &["execution:1".into()], 0, 10)
            .unwrap();
        assert!(weak.is_none());

        // Enough evidence across a wide span: promoted.
        let strong = e
            .consolidate(
                "changes to X break Y",
                &[
                    "execution:1".into(),
                    "execution:2".into(),
                    "execution:3".into(),
                ],
                0,
                10 * 24 * 3600,
            )
            .unwrap();
        assert!(strong.is_some());
        assert_eq!(e.active_knowledge().unwrap().len(), 1);
    }

    #[test]
    fn promotion_bridge_reuses_the_gate_and_templates_statements() {
        let e = engine();
        // Too few / too fast: the shared count+span gate rejects it — no new
        // threshold, so coincidence is not laundered into knowledge.
        let weak = e
            .promote_signals(&[SignalPromotion {
                subject: "artifact:src/x.rs".into(),
                evidence_node_ids: vec!["execution:1".into()],
                first_seen: 0,
                last_seen: 10,
                statement: None,
            }])
            .unwrap();
        assert!(weak.is_empty());
        assert!(e.active_knowledge().unwrap().is_empty());

        // Proven across a wide span: promoted with a deterministic templated
        // statement (no model), and the evidence node ids retained for later
        // conformance intersection.
        let strong = e
            .promote_signals(&[SignalPromotion {
                subject: "artifact:src/x.rs".into(),
                evidence_node_ids: vec![
                    "execution:1".into(),
                    "execution:2".into(),
                    "execution:3".into(),
                ],
                first_seen: 0,
                last_seen: 10 * 24 * 3600,
                statement: None,
            }])
            .unwrap();
        assert_eq!(strong.len(), 1);
        assert!(strong[0].statement.contains("artifact:src/x.rs"));
        assert_eq!(
            strong[0].referenced_nodes(),
            vec!["execution:1", "execution:2", "execution:3"]
        );
        assert_eq!(e.active_knowledge().unwrap().len(), 1);
    }
}
